"use strict";(self.webpackChunkweaver_orm_docs=self.webpackChunkweaver_orm_docs||[]).push([[724],{9301(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"category","label":"Getting Started","collapsed":false,"items":[{"type":"link","label":"Introdu\xe7\xe3o","href":"/weaverORM/pt/docs/","docId":"intro","unlisted":false},{"type":"link","label":"Instala\xe7\xe3o","href":"/weaverORM/pt/docs/installation","docId":"installation","unlisted":false},{"type":"link","label":"In\xedcio R\xe1pido","href":"/weaverORM/pt/docs/quick-start","docId":"quick-start","unlisted":false},{"type":"link","label":"Configura\xe7\xe3o do Symfony","href":"/weaverORM/pt/docs/configuration","docId":"configuration","unlisted":false}],"collapsible":true},{"type":"category","label":"Entity Mapping","items":[{"type":"link","label":"Mapeamento de Entidades","href":"/weaverORM/pt/docs/entity-mapping","docId":"entity-mapping","unlisted":false},{"type":"link","label":"Rela\xe7\xf5es","href":"/weaverORM/pt/docs/relations","docId":"relations","unlisted":false},{"type":"link","label":"Objetos Embutidos","href":"/weaverORM/pt/docs/embeddable","docId":"embeddable","unlisted":false},{"type":"link","label":"Mapeamento de Heran\xe7a","href":"/weaverORM/pt/docs/inheritance","docId":"inheritance","unlisted":false},{"type":"link","label":"Concerns e Traits","href":"/weaverORM/pt/docs/concerns","docId":"concerns","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Entity Workspace","items":[{"type":"link","label":"EntityWorkspace","href":"/weaverORM/pt/docs/workspace","docId":"workspace","unlisted":false},{"type":"link","label":"Reposit\xf3rios","href":"/weaverORM/pt/docs/repositories","docId":"repositories","unlisted":false},{"type":"link","label":"Query Builder","href":"/weaverORM/pt/docs/querying","docId":"querying","unlisted":false},{"type":"link","label":"Hooks de Ciclo de Vida","href":"/weaverORM/pt/docs/lifecycle","docId":"lifecycle","unlisted":false},{"type":"link","label":"Transa\xe7\xf5es","href":"/weaverORM/pt/docs/transactions","docId":"transactions","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Schema & Migrations","items":[{"type":"link","label":"Schema e Migra\xe7\xf5es","href":"/weaverORM/pt/docs/schema-migrations","docId":"schema-migrations","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Advanced","items":[{"type":"link","label":"Cole\xe7\xf5es de Entidades","href":"/weaverORM/pt/docs/collections","docId":"collections","unlisted":false},{"type":"link","label":"Pagina\xe7\xe3o","href":"/weaverORM/pt/docs/pagination","docId":"pagination","unlisted":false},{"type":"link","label":"Testes","href":"/weaverORM/pt/docs/testing","docId":"testing","unlisted":false},{"type":"link","label":"Migra\xe7\xe3o do Doctrine","href":"/weaverORM/pt/docs/doctrine-bridge","docId":"doctrine-bridge","unlisted":false},{"type":"link","label":"Suporte MongoDB","href":"/weaverORM/pt/docs/mongodb","docId":"mongodb","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"PyroSQL","items":[{"type":"link","label":"Overview","href":"/weaverORM/pt/docs/pyrosql/overview","docId":"pyrosql/overview","unlisted":false},{"type":"link","label":"Time Travel","href":"/weaverORM/pt/docs/pyrosql/time-travel","docId":"pyrosql/time-travel","unlisted":false},{"type":"link","label":"Branches","href":"/weaverORM/pt/docs/pyrosql/branches","docId":"pyrosql/branches","unlisted":false},{"type":"link","label":"CDC","href":"/weaverORM/pt/docs/pyrosql/cdc","docId":"pyrosql/cdc","unlisted":false},{"type":"link","label":"Approximate Queries","href":"/weaverORM/pt/docs/pyrosql/approximate","docId":"pyrosql/approximate","unlisted":false},{"type":"link","label":"Vector Search","href":"/weaverORM/pt/docs/pyrosql/vectors","docId":"pyrosql/vectors","unlisted":false},{"type":"link","label":"WASM UDFs","href":"/weaverORM/pt/docs/pyrosql/wasm-udfs","docId":"pyrosql/wasm-udfs","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"collections":{"id":"collections","title":"Cole\xe7\xf5es de Entidades","description":"Weaver\\\\ORM\\\\Collection\\\\EntityCollection is a typed, immutable-by-default collection returned by repositories and query builders. Every method that would mutate the collection returns a new EntityCollection instance, so the original is never modified. This makes collections safe to pass around without defensive copying.","sidebar":"tutorialSidebar"},"concerns":{"id":"concerns","title":"Concerns e Traits","description":"Weaver ORM provides built-in concerns \u2014 PHP traits that add common behaviour (timestamps, soft deletes, UUID generation) to entities and their mappers. They follow the same explicit-mapping philosophy: each concern contributes both the entity-side PHP logic and the mapper-side column definitions.","sidebar":"tutorialSidebar"},"configuration":{"id":"configuration","title":"Configura\xe7\xe3o do Symfony","description":"O Weaver ORM \xe9 configurado via config/packages/weaver.yaml. Esta p\xe1gina cobre todas as op\xe7\xf5es dispon\xedveis.","sidebar":"tutorialSidebar"},"doctrine-bridge":{"id":"doctrine-bridge","title":"Migra\xe7\xe3o do Doctrine","description":"Weaver ORM ships a compatibility bridge that lets you migrate an existing Doctrine ORM codebase incrementally. The bridge exposes the familiar Doctrine EntityManager API as a thin, deprecated wrapper over the Weaver internals so that existing code continues to compile and run while you migrate file by file.","sidebar":"tutorialSidebar"},"embeddable":{"id":"embeddable","title":"Objetos Embutidos","description":"An embeddable (also called a value object in DDD terminology) is a PHP class whose properties are stored as columns in the parent entity\'s table \u2014 no join, no separate table. Weaver manages the column mapping and prefix logic via a dedicated AbstractEmbeddableMapper.","sidebar":"tutorialSidebar"},"entity-mapping":{"id":"entity-mapping","title":"Mapeamento de Entidades","description":"O Weaver ORM separa os objetos de dom\xednio dos metadados de persist\xeancia colocando todas as informa\xe7\xf5es de mapeamento em uma classe mapper dedicada. Esta p\xe1gina cobre todos os aspectos da configura\xe7\xe3o do mapper.","sidebar":"tutorialSidebar"},"inheritance":{"id":"inheritance","title":"Mapeamento de Heran\xe7a","description":"Weaver ORM supports three inheritance patterns. Choose based on how similar your subclass schemas are and how often you need to query across all types in a single SELECT.","sidebar":"tutorialSidebar"},"installation":{"id":"installation","title":"Instala\xe7\xe3o","description":"Requisitos","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"O que \xe9 o Weaver ORM?","description":"O Weaver ORM \xe9 um mapeador objeto-relacional (ORM) para PHP 8.4+ em aplica\xe7\xf5es Symfony constru\xeddo sobre uma \xfanica premissa: seus objetos de dom\xednio n\xe3o devem ter nenhum conhecimento do banco de dados. Sem anota\xe7\xf5es nas classes de entidade, sem gera\xe7\xe3o de proxies, sem reflex\xe3o em tempo de execu\xe7\xe3o \u2014 apenas objetos PHP simples e classes de mapeamento expl\xedcitas que traduzem entre eles e o SQL.","sidebar":"tutorialSidebar"},"lifecycle":{"id":"lifecycle","title":"Hooks de Ciclo de Vida","description":"Weaver ORM provides a set of PHP 8 attributes that let you attach callbacks directly to entity methods. These callbacks are invoked at specific points in the entity\'s persistence lifecycle \u2014 before or after insert, update, delete, and load operations.","sidebar":"tutorialSidebar"},"mongodb":{"id":"mongodb","title":"Suporte MongoDB","description":"Weaver ORM includes first-class support for MongoDB through a document-oriented abstraction layer. The API mirrors the relational ORM closely, so switching between SQL and MongoDB entities requires minimal mental overhead.","sidebar":"tutorialSidebar"},"pagination":{"id":"pagination","title":"Pagina\xe7\xe3o","description":"Weaver ORM provides three paginator types for different use cases: Page (standard offset pagination), SimplePage (lightweight, no total count), and CursorPage (cursor-based, ideal for infinite scroll and large datasets).","sidebar":"tutorialSidebar"},"pyrosql/approximate":{"id":"pyrosql/approximate","title":"Consultas Aproximadas","description":"Approximate Query Processing (AQP) lets PyroSQL answer aggregate questions \u2014 COUNT, SUM, AVG \u2014 by scanning a statistical sample of the data instead of reading every row. The result is returned in milliseconds even on tables with billions of rows, at the cost of a small, bounded error margin.","sidebar":"tutorialSidebar"},"pyrosql/branches":{"id":"pyrosql/branches","title":"Branching","description":"PyroSQL branching works like Git branches, but for data. A branch is a lightweight, copy-on-write snapshot of the entire database. It can be queried and mutated independently of its parent, then either merged back or discarded \u2014 without affecting any other branch.","sidebar":"tutorialSidebar"},"pyrosql/cdc":{"id":"pyrosql/cdc","title":"Captura de Dados de Mudan\xe7a","description":"Change Data Capture (CDC) is a technique for observing every INSERT, UPDATE, and DELETE that occurs on a database table, in real time, without polling. PyroSQL exposes a streaming SUBSCRIBE TO CHANGES ON  SQL command that yields rows as DML operations are committed to the WAL (Write-Ahead Log). Weaver ORM wraps this mechanism in CdcSubscriber and hydrates each row into a typed CdcEvent.","sidebar":"tutorialSidebar"},"pyrosql/overview":{"id":"pyrosql/overview","title":"Vis\xe3o Geral do PyroSQL","description":"PyroSQL is a custom database engine written in Rust. It speaks the PostgreSQL wire protocol version 3 natively, which means every PostgreSQL-compatible library, driver, and tool connects to it without modification \u2014 including the PDO pgsql driver that Doctrine DBAL uses under the hood.","sidebar":"tutorialSidebar"},"pyrosql/time-travel":{"id":"pyrosql/time-travel","title":"Consultas de Viagem no Tempo","description":"PyroSQL maintains a complete history of every row that has ever existed in the database. Time travel queries let you read data as it appeared at any previous point in time by appending an AS OF clause to the FROM clause of a SELECT statement. This is useful for audit log replay, point-in-time recovery, compliance reports, and debugging data mutations.","sidebar":"tutorialSidebar"},"pyrosql/vectors":{"id":"pyrosql/vectors","title":"Busca Vetorial","description":"Vector similarity search lets you find rows whose stored embedding vectors are closest to a query vector. This is the foundation of semantic search, recommendation systems, and AI-powered retrieval \u2014 where \\"closeness\\" is measured by cosine distance, Euclidean (L2) distance, or dot product, rather than exact string or numeric equality.","sidebar":"tutorialSidebar"},"pyrosql/wasm-udfs":{"id":"pyrosql/wasm-udfs","title":"WASM UDFs","description":"PyroSQL supports WebAssembly User-Defined Functions (WASM UDFs) \u2014 custom SQL functions compiled to the WebAssembly binary format and executed inside the database engine. WASM UDFs run in a sandboxed, deterministic environment with near-native performance and no external network access. Once registered, they are callable from any SQL statement.","sidebar":"tutorialSidebar"},"querying":{"id":"querying","title":"Query Builder","description":"EntityQueryBuilder is Weaver ORM\'s fluent query API. It wraps Doctrine DBAL with full entity awareness: results are automatically hydrated into entity objects, global scopes are applied, and soft-delete filters are managed transparently.","sidebar":"tutorialSidebar"},"quick-start":{"id":"quick-start","title":"In\xedcio R\xe1pido","description":"Este guia percorre um exemplo completo funcional: definindo uma entidade User, escrevendo seu mapper e realizando opera\xe7\xf5es b\xe1sicas de persist\xeancia usando o EntityWorkspace.","sidebar":"tutorialSidebar"},"relations":{"id":"relations","title":"Rela\xe7\xf5es","description":"O Weaver ORM define todos os metadados de rela\xe7\xe3o dentro da classe mapper da entidade via um RelationMap. N\xe3o h\xe1 atributos nas propriedades da entidade e nenhuma reflex\xe3o em tempo de execu\xe7\xe3o. As rela\xe7\xf5es s\xe3o sempre carregadas de forma expl\xedcita \u2014 o Weaver nunca emite consultas surpresa por baixo dos panos.","sidebar":"tutorialSidebar"},"repositories":{"id":"repositories","title":"Reposit\xf3rios","description":"Repositories are the primary way to read entities from the database. Every entity has a corresponding repository that encapsulates all query logic for that entity, keeping controllers and services free of raw SQL or query-builder calls.","sidebar":"tutorialSidebar"},"schema-migrations":{"id":"schema-migrations","title":"Schema e Migra\xe7\xf5es","description":"Weaver ORM generates SQL DDL directly from your mapper classes. The SchemaGenerator reads every registered mapper, converts it into a Doctrine DBAL Schema object, and can create, update, or drop your database schema through a set of Symfony console commands.","sidebar":"tutorialSidebar"},"testing":{"id":"testing","title":"Testes","description":"Weaver ORM provides a dedicated testing toolkit that makes it straightforward to write fast, reliable tests for code that interacts with the database.","sidebar":"tutorialSidebar"},"transactions":{"id":"transactions","title":"Transa\xe7\xf5es","description":"Weaver ORM provides TransactionManager, a dedicated service for managing database transactions. It supports simple atomic blocks, manual begin/commit/rollback, nested transactions via savepoints, and optimistic locking.","sidebar":"tutorialSidebar"},"workspace":{"id":"workspace","title":"EntityWorkspace","description":"EntityWorkspace is Weaver ORM\'s central unit-of-work service. It tracks entities across a single request, batches all writes, and flushes them to the database in a single coordinated operation. Think of it as the improved successor to Doctrine\'s EntityManager, redesigned for clarity, worker safety, and explicit intent.","sidebar":"tutorialSidebar"}}}}')}}]);